import { useQueryClient } from "@tanstack/react-query";
import type { Plan } from "ui";
import { fetchProvidersWithRegions } from "./fetchProvidersWithRegions";
import { providerQueries } from "./queryKeys";
import { useKms } from "./useApi";

export function useProvidersWithRegionsQuery() {
  const queryClient = useQueryClient();
  const getKms = useKms();

  return (plan: Plan) => {
    const kms = getKms();
    return queryClient.fetchQuery({
      queryKey: providerQueries.list({ plan }),
      queryFn: () =>
        fetchProvidersWithRegions(
          (...args) => kms.getCloudProviders(...args),
          (...args) => kms.getCloudProviderRegions(...args),
          plan
        ),
      staleTime: Infinity,
    });
  };
}
